mapper.select:
SELECT s.*, u.nickname as student_name, c.course_name FROM stat_learning_summary s LEFT JOIN sys_user u ON s.student_id = u.user_id LEFT JOIN edu_course c ON s.course_id = c.course_id
AND u.nickname LIKE CONCAT('%', #{studentName}, '%')
AND s.last_active_time >= #{startTime}
AND s.last_active_time <= #{endTime}
ORDER BY s.last_active_time DESC

mapper.insert:
INSERT INTO stat_learning_summary ( student_id, course_id, total_study_time, exam_avg_score, assignment_completion, last_active_time ) SELECT cs.student_id, cs.course_id, COALESCE(SUM(lb.duration), 0) as total_study_time, COALESCE( ( SELECT AVG(ea.score) FROM exam_paper ep JOIN exam_record er ON ep.exam_id = er.exam_id JOIN exam_answer ea ON er.record_id = ea.record_id WHERE ep.course_id = cs.course_id AND er.student_id = cs.student_id ), 0 ) as exam_avg_score, ROUND( ( COUNT(DISTINCT CASE WHEN lb.behavior_type = 'complete_resource' THEN lb.resource_id END) * 100.0 ) / NULLIF( ( SELECT COUNT(DISTINCT tr.resource_id) FROM edu_teaching_resource tr WHERE tr.course_id = cs.course_id ), 0 ), 2 ) as assignment_completion, MAX(lb.create_time) as last_active_time FROM edu_course_student cs LEFT JOIN stat_learning_behavior lb ON cs.student_id = lb.student_id AND cs.course_id = lb.course_id
AND cs.student_id = #{studentId}
AND cs.course_id = #{courseId}
AND lb.create_time >= #{startTime}
AND lb.create_time <= #{endTime}
GROUP BY cs.student_id, cs.course_id ON DUPLICATE KEY UPDATE total_study_time = VALUES(total_study_time), exam_avg_score = VALUES(exam_avg_score), assignment_completion = VALUES(assignment_completion), last_active_time = VALUES(last_active_time)
